// Cloudflare Worker: API Integration with SendGrid and Stripe
// wrangler.toml configuration should include:
// [vars]
// ALLOWED_ORIGINS = "https://yourdomain.com"
// 
// [secrets]
// SENDGRID_API_KEY
// STRIPE_SECRET_KEY
// API_AUTH_TOKEN

export default {
  async fetch(request, env, ctx) {
    const corsHeaders = {
      'Access-Control-Allow-Origin': env.ALLOWED_ORIGINS || '*',
      'Access-Control-Allow-Methods': 'GET, POST, OPTIONS',
      'Access-Control-Allow-Headers': 'Content-Type, Authorization',
      'Access-Control-Max-Age': '86400',
    };

    // Handle CORS preflight
    if (request.method === 'OPTIONS') {
      return new Response(null, { status: 204, headers: corsHeaders });
    }

    try {
      // Authenticate the request
      const authError = authenticateRequest(request, env);
      if (authError) {
        return jsonResponse(401, { error: authError }, corsHeaders);
      }

      const url = new URL(request.url);
      const path = url.pathname;

      // Route requests
      switch (true) {
        // Email endpoints
        case path === '/api/email/send' && request.method === 'POST':
          return await handleSendEmail(request, env, corsHeaders);

        // Stripe payment endpoints
        case path === '/api/payments/create-intent' && request.method === 'POST':
          return await handleCreatePaymentIntent(request, env, corsHeaders);

        case path === '/api/payments/customers' && request.method === 'POST':
          return await handleCreateCustomer(request, env, corsHeaders);

        case path === '/api/payments/customers' && request.method === 'GET':
          return await handleGetCustomer(request, env, corsHeaders);

        case path === '/api/payments/subscriptions' && request.method === 'POST':
          return await handleCreateSubscription(request, env, corsHeaders);

        case path === '/api/payments/subscriptions/cancel' && request.method === 'POST':
          return await handleCancelSubscription(request, env, corsHeaders);

        // Stripe webhook (no auth token required, uses Stripe signature)
        case path === '/api/webhooks/stripe' && request.method === 'POST':
          return await handleStripeWebhook(request, env, corsHeaders);

        // Health check
        case path === '/api/health' && request.method === 'GET':
          return jsonResponse(200, {
            status: 'healthy',
            timestamp: new Date().toISOString(),
            services: ['sendgrid', 'stripe'],
          }, corsHeaders);

        default:
          return jsonResponse(404, { error: 'Not found' }, corsHeaders);
      }
    } catch (error) {
      console.error('Unhandled error:', error.message, error.stack);
      return jsonResponse(500, {
        error: 'Internal server error',
        message: error.message,
      }, corsHeaders);
    }
  },
};

// ==================== Authentication ====================

function authenticateRequest(request, env) {
  const url = new URL(request.url);

  // Skip auth for health check and webhooks
  if (url.pathname === '/api/health' || url.pathname.startsWith('/api/webhooks/')) {
    return null;
  }

  const authHeader = request.headers.get('Authorization');
  if (!authHeader) {
    return 'Missing Authorization header';
  }

  const [scheme, token] = authHeader.split(' ');
  if (scheme !== 'Bearer' || !token) {
    return 'Invalid Authorization format. Expected: Bearer <token>';
  }

  if (token !== env.API_AUTH_TOKEN) {
    return 'Invalid authentication token';
  }

  return null;
}

// ==================== SendGrid Email ====================

async function handleSendEmail(request, env, corsHeaders) {
  const body = await parseJsonBody(request);
  if (body.error) {
    return jsonResponse(400, { error: body.error }, corsHeaders);
  }

  const { to, from, subject, text, html, templateId, dynamicTemplateData } = body.data;

  // Validation
  const validationErrors = [];
  if (!to) validationErrors.push('to is required');
  if (!from) validationErrors.push('from is required');
  if (!subject && !templateId) validationErrors.push('subject or templateId is required');
  if (!text && !html && !templateId) validationErrors.push('text, html, or templateId is required');

  if (validationErrors.length > 0) {
    return jsonResponse(400, { error: 'Validation failed', details: validationErrors }, corsHeaders);
  }

  // Validate email format
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  const toAddresses = Array.isArray(to) ? to : [to];
  for (const email of toAddresses) {
    const addr = typeof email === 'string' ? email : email.email;
    if (!emailRegex.test(addr)) {
      return jsonResponse(400, { error: `Invalid email address: ${addr}` }, corsHeaders);
    }
  }

  const personalizations = [{
    to: toAddresses.map(addr =>
      typeof addr === 'string' ? { email: addr } : addr
    ),
  }];

  if (templateId && dynamicTemplateData) {
    personalizations[0].dynamic_template_data = dynamicTemplateData;
  }

  const sendgridPayload = {
    personalizations,
    from: typeof from === 'string' ? { email: from } : from,
  };

  if (templateId) {
    sendgridPayload.template_id = templateId;
  } else {
    sendgridPayload.subject = subject;
    sendgridPayload.content = [];
    if (text) sendgridPayload.content.push({ type: 'text/plain', value: text });
    if (html) sendgridPayload.content.push({ type: 'text/html', value: html });
  }

  const result = await sendGridRequest('/v3/mail/send', 'POST', sendgridPayload, env);

  if (!result.ok) {
    console.error('SendGrid error:', JSON.stringify(result.data));
    return jsonResponse(result.status === 429 ? 429 : 502, {
      error: 'Failed to send email',
      details: result.data,
    }, corsHeaders);
  }

  return jsonResponse(200, {
    success: true,
    message: 'Email sent successfully',
    messageId: result.headers?.get('x-message-id') || null,
  }, corsHeaders);
}

async function sendGridRequest(path, method, body, env) {
  const url = `https://api.sendgrid.com${path}`;

  try {
    const response = await fetch(url, {
      method,
      headers: {
        'Authorization': `Bearer ${env.SENDGRID_API_KEY}`,
        'Content-Type': 'application/json',
      },
      body: body ? JSON.stringify(body) : undefined,
    });

    let data = null;
    const contentType = response.headers.get('content-type');
    if (contentType && contentType.includes('application/json')) {
      data = await response.json();
    }

    return {
      ok: response.ok,
      status: response.status,
      data,
      headers: response.headers,
    };
  } catch (error) {
    console.error('SendGrid request failed:', error.message);
    return {
      ok: false,
      status: 503,
      data: { error: 'SendGrid service unavailable', message: error.message },
    };
  }
}

// ==================== Stripe Payments ====================

async function handleCreatePaymentIntent(request, env, corsHeaders) {
  const body = await parseJsonBody(request);
  if (body.error) {
    return jsonResponse(400, { error: body.error }, corsHeaders);
  }

  const { amount, currency, customerId, metadata, description, receiptEmail, automaticPaymentMethods } = body.data;

  // Validation
  if (!amount || typeof amount !== 'number' || amount < 50) {
    return jsonResponse(400, { error: 'amount must be a number >= 50 (in cents)' }, corsHeaders);
  }
  if (!currency) {
    return jsonResponse(400, { error: 'currency is required' }, corsHeaders);
  }

  const params = new URLSearchParams();
  params.append('amount', String(Math.round(amount)));
  params.append('currency', currency.toLowerCase());

  if (customerId) params.append('customer', customerId);
  if (description) params.append('description', description);
  if (receiptEmail) params.append('receipt_email', receiptEmail);

  if (automaticPaymentMethods !== false) {
    params.append('automatic_payment_methods[enabled]', 'true');
  }

  if (metadata && typeof metadata === 'object') {
    for (const [key, value] of Object.entries(metadata)) {
      params.append(`metadata[${key}]`, String(value));
    }
  }

  const result = await stripeRequest('/v1/payment_intents', 'POST', params, env);

  if (!result.ok) {
    return handleStripeError(result, corsHeaders);
  }

  return jsonResponse(200, {
    success: true,
    paymentIntent: {
      id: result.data.id,
      clientSecret: result.data.client_secret,
      amount: result.data.amount,
      currency: result.data.currency,
      status: result.data.status,
    },
  }, corsHeaders);
}

async function handleCreateCustomer(request, env, corsHeaders) {
  const body = await parseJsonBody(request);
  if (body.error) {
    return jsonResponse(400, { error: body.error }, corsHeaders);
  }

  const { email, name, phone, metadata, description } = body.data;

  if (!email) {
    return jsonResponse(400, { error: 'email is required' }, corsHeaders);
  }

  const params = new URLSearchParams();
  params.append('email', email);
  if (name) params.append('name', name);
  if (phone) params.append('phone', phone);
  if (description) params.append('description', description);

  if (metadata && typeof metadata === 'object') {
    for (const [key, value] of Object.entries(metadata)) {
      params.append(`metadata[${key}]`, String(value));
    }
  }

  const result = await stripeRequest('/v1/customers', 'POST', params, env);

  if (!result.ok) {
    return handleStripeError(result, corsHeaders);
  }

  return jsonResponse(201, {
    success: true,
    customer: {
      id: result.data.id,
      email: result.data.email,
      name: result.data.name,
      created: result.data.created,
    },
  }, corsHeaders);
}

async function handleGetCustomer(request, env, corsHeaders) {
  const url = new URL(request.url);
  const customerId = url.searchParams.get('id');
  const email = url.searchParams.get('email');

  if (!customerId && !email) {
    return jsonResponse(400, { error: 'id or email query parameter is required' }, corsHeaders);
  }

  let result;

  if (customerId) {
    result = await stripeRequest(`/v1/customers/${encodeURIComponent(customerId)}`, 'GET', null, env);
  } else {
    const params = new URLSearchParams();
    params.append('email', email);
    params.append('limit', '1');
    result = await stripeRequest(`/v1/customers?${params.toString()}`, 'GET', null, env);
  }

  if (!result.ok) {
    return handleStripeError(result, corsHeaders);
  }

  if (result.data.object === 'list') {
    const customers = result.data.data;
    if (customers.length === 0) {
      return jsonResponse(404, { error: 'Customer not found' }, corsHeaders);
    }
    return jsonResponse(200, {
      success: true,
      customer: formatCustomer(customers[0]),
    }, corsHeaders);
  }

  return jsonResponse(200, {
    success: true,
    customer: formatCustomer(result.data),
  }, corsHeaders);
}

async function handleCreateSubscription(request, env, corsHeaders) {
  const body = await parseJsonBody(request);
  if (body.error) {
    return jsonResponse(400, { error: body.error }, corsHeaders);
  }

  const { customerId, priceId, trialPeriodDays, metadata, paymentBehavior } = body.data;

  if (!customerId) {
    return jsonResponse(400, { error: 'customerId is required' }, corsHeaders);
  }
  if (!priceId) {
    return jsonResponse(400, { error: 'priceId is required' }, corsHeaders);
  }

  const params = new URLSearchParams();
  params.append('customer', customerId);
  params.append('items[0][price]', priceId);
  params.append('payment_behavior', paymentBehavior || 'default_incomplete');
  params.append('payment_settings[save_default_payment_method]', 'on_subscription');
  params.append('expand[]', 'latest_invoice.payment_intent');

  if (trialPeriodDays) {
    params.append('trial_period_days', String(trialPeriodDays));
  }

  if (metadata && typeof metadata === 'object') {
    for (const [key, value] of Object.entries(metadata)) {
      params.append(`metadata[${key}]`, String(value));
    }
  }

  const result = await stripeRequest('/v1/subscriptions', 'POST', params, env);

  if (!result.ok) {
    return handleStripeError(result, corsHeaders);
  }

  const subscription = result.data;
  const responseData = {
    success: true,
    subscription: {
      id: subscription.id,
      status: subscription.status,
      currentPeriodStart: subscription.current_period_start,
      currentPeriodEnd: subscription.current_period_end,
      trialEnd: subscription.trial_end,
    },
  };

  // Include client secret for incomplete subscriptions
  if (subscription.latest_invoice?.payment_intent?.client_secret) {
    responseData.clientSecret = subscription.latest_invoice.payment_intent.client_secret;
  }

  return jsonResponse(201, responseData, corsHeaders);
}

async function handleCancelSubscription(request, env, corsHeaders) {
  const body = await parseJsonBody(request);
  if (body.error) {
    return jsonResponse(400, { error: body.error }, corsHeaders);
  }

  const { subscriptionId, cancelAtPeriodEnd } = body.data;

  if (!subscriptionId) {
    return jsonResponse(400, { error: 'subscriptionId is required' }, corsHeaders);
  }

  let result;

  if (cancelAtPeriodEnd) {
    // Cancel at end of billing period
    const params = new URLSearchParams();
    params.append('cancel_at_period_end', 'true');
    result = await stripeRequest(`/v1/subscriptions/${encodeURIComponent(subscriptionId)}`, 'POST', params, env);
  } else {
    // Cancel immediately
    result = await stripeRequest(`/v1/subscriptions/${encodeURIComponent(subscriptionId)}`, 'DELETE', null, env);
  }

  if (!result.ok) {
    return handleStripeError(result, corsHeaders);
  }

  return jsonResponse(200, {
    success: true,
    subscription: {
      id: result.data.id,
      status: result.data.status,
      cancelAtPeriodEnd: result.data.cancel_at_period_end,
      canceledAt: result.data.canceled_at,
      currentPeriodEnd: result.data.current_period_end,
    },
  }, corsHeaders);
}

async function handleStripeWebhook(request, env, corsHeaders) {
  const signature = request.headers.get('stripe-signature');
  if (!signature) {
    return jsonResponse(400, { error: 'Missing stripe-signature header' }, corsHeaders);
  }

  const rawBody = await request.text();

  // Verify webhook signature
  const isValid = await verifyStripeSignature(rawBody, signature, env.STRIPE_WEBHOOK_SECRET);
  if (!isValid) {
    console.error('Invalid Stripe webhook signature');
    return jsonResponse(401, { error: 'Invalid signature' }, corsHeaders);
  }

  let event;
  try {
    event = JSON.parse(rawBody);
  } catch (e) {
    return jsonResponse(400, { error: 'Invalid JSON body' }, corsHeaders);
  }

  console.log(`Stripe webhook received: ${event.type}, id: ${event.id}`);

  // Process webhook events
  switch (event.type) {
    case 'payment_intent.succeeded':
      await handlePaymentIntentSucceeded(event.data.object, env);
      break;

    case 'payment_intent.payment_failed':
      await handlePaymentIntentFailed(event.data.object, env);
      break;

    case 'customer.subscription.created':
    case 'customer.subscription.updated':
      await handleSubscriptionUpdate(event.data.object, env);
      break;

    case 'customer.subscription.deleted':
      await handleSubscriptionDeleted(event.data.object, env);
      break;

    case 'invoice.payment_succeeded':
      await handleInvoicePaymentSucceeded(event.data.object, env);
      break;

    case 'invoice.payment_failed':
      await handleInvoicePaymentFailed(event.data.object, env);
      break;

    default:
      console.log(`Unhandled Stripe event type: ${event.type}`);
  }

  return jsonResponse(200, { received: true }, corsHeaders);
}

