// Stripe signature verification
async function verifyStripeSignature(payload, sigHeader, secret) {
  if (!secret) {
    console.warn('STRIPE_WEBHOOK_SECRET not set, skipping signature verification');
    return true;
  }

  try {
    const pairs = sigHeader.split(',');
    let timestamp = null;
    const signatures = [];

    for (const pair of pairs) {
      const [key, value] = pair.split('=');
      if (key === 't') timestamp = value;
      if (key === 'v1') signatures.push(value);
    }

    if (!timestamp || signatures.length === 0) {
      return false;
    }

    // Check timestamp tolerance (5 minutes)
    const currentTime = Math.floor(Date.now() / 1000);
    if (Math.abs(currentTime - parseInt(timestamp)) > 300) {
      console.error('Stripe webhook timestamp too old');
      return false;
    }

    const signedPayload = `${timestamp}.${payload}`;
    const encoder = new TextEncoder();

    const key = await crypto.subtle.importKey(
      'raw',
      encoder.encode(secret),
      { name: 'HMAC', hash: 'SHA-256' },
      false,
      ['sign']
    );

    const signatureBuffer = await crypto.subtle.sign(
      'HMAC',
      key,
      encoder.encode(signedPayload)
    );

    const computedSignature = Array.from(new Uint8Array(signatureBuffer))
      .map(b => b.toString(16).padStart(2, '0'))
      .join('');

    return signatures.some(sig => timeSafeEqual(sig, computedSignature));
  } catch (error) {
    console.error('Signature verification error:', error.message);
    return false;
  }
}

function timeSafeEqual(a, b) {
  if (a.length !== b.length) return false;
  let result = 0;
  for (let i = 0; i < a.length; i++) {
    result |= a.charCodeAt(i) ^ b.charCodeAt(i);
  }
  return result === 0;
}

// Stripe API helper
async function stripeRequest(path, method, params, env) {
  const url = `https://api.stripe.com${path}`;

  const options = {
    method,
    headers: {
      'Authorization': `Bearer ${env.STRIPE_SECRET_KEY}`,
      'Stripe-Version': '2023-10-16',
    },
  };

  if (params && (method === 'POST' || method === 'PUT' || method === 'PATCH')) {
    options.headers['Content-Type'] = 'application/x-www-form-urlencoded';
    options.body = params.toString();
  }

  try {
    const response = await fetch(url, options);
    const data = await response.json();

    return {
      ok: response.ok,
      status: response.status,
      data,
    };
  } catch (error) {
    console.error('Stripe request failed:', error.message);
    return {
      ok: false,
      status: 503,
      data: { error: { type: 'api_connection_error', message: 'Stripe service unavailable' } },
    };
  }
}

function handleStripeError(result, corsHeaders) {
  const stripeError = result.data?.error || {};
  const statusMap = {
    'card_error': 402,
    'rate_limit_error': 429,
    'invalid_request_error': 400,
    'authentication_error': 401,
    'api_connection_error': 503,
    'api_error': 502,
  };

  const status = statusMap[stripeError.type] || result.status || 500;

  return jsonResponse(status, {
    error: stripeError.message || 'Stripe API error',
    type: stripeError.type,
    code: stripeError.code,
    param: stripeError.param,
  }, corsHeaders);
}

// ==================== Utility Functions ====================

function formatCustomer(customer) {
  return {
    id: customer.id,
    email: customer.email,
    name: customer.name,
    phone: customer.phone,
    created: customer.created,
    metadata: customer.metadata,
    defaultPaymentMethod: customer.invoice_settings?.default_payment_method,
  };
}

async function parseJsonBody(request) {
  try {
    const contentType = request.headers.get('content-type');
    if (!contentType || !contentType.includes('application/json')) {
      return { error: 'Content-Type must be application/json' };
    }

    const text = await request.text();
    if (!text) {
      return { error: 'Request body is empty' };
    }

    const data = JSON.parse(text);
    return { data };
  } catch (e) {
    return { error: 'Invalid JSON in request body' };
  }
}

function jsonResponse(status, data, corsHeaders = {}) {
  return new Response(JSON.stringify(data), {
    status,
    headers: {
      'Content-Type': 'application/json',
      ...corsHeaders,
    },
  });
}